import { Component, type ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
  errorInfo: { componentStack: string } | null;
}

export class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error, errorInfo: null };
  }

  componentDidCatch(error: Error, errorInfo: { componentStack: string }) {
    console.error('[ErrorBoundary] React error:', error, errorInfo);
    this.setState({ error, errorInfo });

    // Also dispatch as window error for ErrorReporter to catch
    window.dispatchEvent(new ErrorEvent('error', {
      message: `React ErrorBoundary: ${error.message}`,
      error,
    }));
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{
          minHeight: '100vh',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          padding: 24,
          background: '#fef2f2',
          fontFamily: 'system-ui, sans-serif',
        }}>
          <div style={{
            maxWidth: 600,
            width: '100%',
            background: '#fff',
            borderRadius: 16,
            padding: '32px 24px',
            boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)',
            textAlign: 'center',
          }}>
            <div style={{
              width: 64,
              height: 64,
              borderRadius: '50%',
              background: '#fee2e2',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              margin: '0 auto 20px',
            }}>
              <AlertTriangle style={{ width: 32, height: 32, color: '#dc2626' }} />
            </div>

            <h1 style={{ margin: '0 0 8px', fontSize: 22, fontWeight: 700, color: '#991b1b' }}>
              Something went wrong
            </h1>
            <p style={{ margin: '0 0 20px', color: '#7f1d1d', fontSize: 14 }}>
              The app crashed during rendering. Check the error details below.
            </p>

            <div style={{
              background: '#f3f4f6',
              borderRadius: 12,
              padding: 16,
              textAlign: 'left',
              marginBottom: 20,
              overflow: 'auto',
            }}>
              <p style={{ margin: '0 0 8px', fontSize: 13, fontWeight: 600, color: '#1f2937' }}>
                {this.state.error?.message || 'Unknown error'}
              </p>
              {this.state.errorInfo && (
                <pre style={{
                  margin: 0,
                  fontSize: 11,
                  color: '#4b5563',
                  whiteSpace: 'pre-wrap',
                  wordBreak: 'break-word',
                  maxHeight: 200,
                  overflow: 'auto',
                }}>
                  {this.state.errorInfo.componentStack}
                </pre>
              )}
              {this.state.error?.stack && (
                <pre style={{
                  margin: '8px 0 0',
                  fontSize: 11,
                  color: '#4b5563',
                  whiteSpace: 'pre-wrap',
                  wordBreak: 'break-word',
                  maxHeight: 200,
                  overflow: 'auto',
                }}>
                  {this.state.error.stack}
                </pre>
              )}
            </div>

            <button
              onClick={() => window.location.reload()}
              style={{
                display: 'inline-flex',
                alignItems: 'center',
                gap: 8,
                padding: '10px 20px',
                background: '#dc2626',
                color: '#fff',
                border: 'none',
                borderRadius: 8,
                fontSize: 14,
                fontWeight: 600,
                cursor: 'pointer',
              }}
            >
              <RefreshCw style={{ width: 16, height: 16 }} />
              Reload Page
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}
