import { useState, useEffect, useMemo, useCallback } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import type { Job, JobType } from '../types';
import type { GeocodeResult } from '../utils/geocode';
import { DEFAULT_MAP_CENTER, DEFAULT_ZOOM } from '../data/oshkosh-data';
import { Wrench, Trash2, Anchor, AlertTriangle, Navigation, X } from 'lucide-react';

// Fix Leaflet default icon issue in bundlers
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
  iconUrl: icon,
  shadowUrl: iconShadow,
  iconSize: [25, 41],
  iconAnchor: [12, 41]
});

L.Marker.prototype.options.icon = DefaultIcon;

interface JobMapProps {
  jobs: Job[];
  activeFilters: JobType[];
  showUrgentOnly: boolean;
  selectedJobId: number | null;
  onJobSelect: (jobId: number) => void;
  searchLocation?: GeocodeResult | null;
  onMapClick?: (lat: number, lng: number) => void;
}

function hasFiniteCoords(lat: unknown, lng: unknown): lat is number {
  return typeof lat === 'number' && typeof lng === 'number' && Number.isFinite(lat) && Number.isFinite(lng);
}

function MapController({ selectedJobId, jobs, searchLocation }: { selectedJobId: number | null; jobs: Job[]; searchLocation?: GeocodeResult | null }) {
  const map = useMap();
  
  useEffect(() => {
    if (selectedJobId) {
      const job = jobs.find(j => j.id === selectedJobId);
      if (job && hasFiniteCoords(job.lat, job.lng)) {
        map.setView([job.lat, job.lng], 16, { animate: true, duration: 0.5 });
      }
    }
  }, [selectedJobId, jobs, map]);

  useEffect(() => {
    if (searchLocation && hasFiniteCoords(searchLocation.lat, searchLocation.lng)) {
      map.setView([searchLocation.lat, searchLocation.lng], 16, { animate: true, duration: 0.5 });
    }
  }, [searchLocation, map]);

  return null;
}

function MapClickHandler({ onMapClick }: { onMapClick?: (lat: number, lng: number) => void }) {
  useMapEvents({
    click: (e) => {
      if (onMapClick) {
        onMapClick(e.latlng.lat, e.latlng.lng);
      }
    }
  });
  return null;
}

function createCustomIcon(type: JobType, isUrgent: boolean) {
  const color = type === 'install' ? '#22c55e' : type === 'remove' ? '#f59e0b' : '#3b82f6';
  const urgentColor = '#ef4444';
  const fillColor = isUrgent ? urgentColor : color;
  
  return L.divIcon({
    className: 'custom-div-icon',
    html: `<div style="
      width: 28px; 
      height: 28px; 
      background: ${fillColor}; 
      border: 3px solid white; 
      border-radius: 50%; 
      box-shadow: 0 2px 8px rgba(0,0,0,0.4);
      display: flex;
      align-items: center;
      justify-content: center;
      color: white;
      font-size: 12px;
      font-weight: bold;
      ${isUrgent ? 'animation: pulse 2s infinite;' : ''}
    ">${type === 'install' ? 'I' : type === 'remove' ? 'R' : 'S'}</div>`,
    iconSize: [28, 28],
    iconAnchor: [14, 14],
    popupAnchor: [0, -14]
  });
}

// Validate job has valid coordinates
function hasValidCoords(job: Job): boolean {
  return hasFiniteCoords(job.lat, job.lng);
}

export default function JobMap({ jobs, activeFilters, showUrgentOnly, selectedJobId, onJobSelect, searchLocation, onMapClick }: JobMapProps) {
  const [mapCenter] = useState<[number, number]>(DEFAULT_MAP_CENTER);
  const [zoom] = useState(DEFAULT_ZOOM);
  const [clickMarker, setClickMarker] = useState<{lat: number; lng: number} | null>(null);

  const filteredJobs = useMemo(() => {
    return jobs.filter(job => {
      if (!hasValidCoords(job)) return false;
      if (showUrgentOnly && !job.isUrgent) return false;
      return activeFilters.includes(job.type);
    });
  }, [jobs, activeFilters, showUrgentOnly]);

  const handleMapClick = useCallback((lat: number, lng: number) => {
    setClickMarker({ lat, lng });
    if (onMapClick) {
      onMapClick(lat, lng);
    }
  }, [onMapClick]);

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return 'text-green-600 bg-green-50';
      case 'in_progress': return 'text-blue-600 bg-blue-50';
      case 'scheduled': return 'text-amber-600 bg-amber-50';
      case 'pending': return 'text-gray-600 bg-gray-50';
      default: return 'text-gray-600 bg-gray-50';
    }
  };

  const getJobIcon = (type: JobType) => {
    switch (type) {
      case 'install': return <Anchor className="w-4 h-4" />;
      case 'remove': return <Trash2 className="w-4 h-4" />;
      case 'service': return <Wrench className="w-4 h-4" />;
    }
  };

  // Log invalid jobs for debugging
  const invalidJobs = useMemo(() => jobs.filter(j => !hasValidCoords(j)), [jobs]);
  if (invalidJobs.length > 0) {
    console.warn('[JobMap] Skipping jobs with invalid coordinates:', invalidJobs.map(j => ({ id: j.id, lat: j.lat, lng: j.lng })));
  }

  return (
    <div className="relative w-full h-full">
      <MapContainer
        center={mapCenter}
        zoom={zoom}
        style={{ height: '100%', width: '100%' }}
        className="z-0"
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/">CARTO</a>'
          url="https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png"
        />
        
        <MapController selectedJobId={selectedJobId} jobs={jobs} searchLocation={searchLocation} />
        <MapClickHandler onMapClick={handleMapClick} />
        
        {filteredJobs.map(job => (
          <Marker
            key={job.id}
            position={[job.lat, job.lng]}
            icon={createCustomIcon(job.type, job.isUrgent)}
            eventHandlers={{
              click: () => onJobSelect(job.id)
            }}
          >
            <Popup className="custom-popup">
              <div className="min-w-[240px]">
                <div className="flex items-center gap-2 mb-2">
                  {getJobIcon(job.type)}
                  <span className="font-semibold text-gray-900 capitalize">{job.type}</span>
                  {job.isUrgent && (
                    <span className="flex items-center gap-1 text-red-600 text-xs font-medium">
                      <AlertTriangle className="w-3 h-3" />
                      URGENT
                    </span>
                  )}
                </div>
                <p className="text-sm text-gray-700 mb-2">{job.description}</p>
                <div className="flex items-center gap-2 mb-2">
                  <span className={`text-xs px-2 py-1 rounded-full font-medium capitalize ${getStatusColor(job.status)}`}>
                    {job.status.replace('_', ' ')}
                  </span>
                  {job.scheduledDate && (
                    <span className="text-xs text-gray-500">
                      {new Date(job.scheduledDate).toLocaleDateString()}
                    </span>
                  )}
                </div>
                {job.estimatedHours && (
                  <p className="text-xs text-gray-500">Est: {job.estimatedHours} hrs</p>
                )}
                {job.cost && (
                  <p className="text-xs text-gray-500">Cost: ${job.cost.toLocaleString()}</p>
                )}
              </div>
            </Popup>
          </Marker>
        ))}

        {/* Click marker for adding new jobs */}
        {clickMarker && (
          <Marker
            position={[clickMarker.lat, clickMarker.lng]}
            icon={L.divIcon({
              className: 'custom-div-icon',
              html: `<div style="
                width: 28px; 
                height: 28px; 
                background: #8b5cf6; 
                border: 3px solid white; 
                border-radius: 50%; 
                box-shadow: 0 2px 8px rgba(0,0,0,0.4);
                display: flex;
                align-items: center;
                justify-content: center;
                color: white;
                font-size: 16px;
                font-weight: bold;
              ">+</div>`,
              iconSize: [28, 28],
              iconAnchor: [14, 14]
            })}
          >
            <Popup>
              <div className="text-center">
                <p className="text-sm font-medium text-gray-900 mb-2">New Location</p>
                <p className="text-xs text-gray-500 mb-3">
                  {clickMarker.lat.toFixed(5)}, {clickMarker.lng.toFixed(5)}
                </p>
                <button className="bg-dock-blue text-white text-xs px-3 py-2 rounded-lg hover:bg-blue-600 transition-colors">
                  Add Job Here
                </button>
              </div>
            </Popup>
          </Marker>
        )}
      </MapContainer>

      {/* Job count badge */}
      <div className="absolute top-4 right-4 z-[400] bg-white rounded-lg shadow-lg px-4 py-2">
        <span className="text-sm font-medium text-gray-700">
          {filteredJobs.length} job{filteredJobs.length !== 1 ? 's' : ''} on map
        </span>
      </div>

      {/* Map controls */}
      <div className="absolute bottom-4 right-4 z-[400] flex flex-col gap-2">
        <button
          onClick={() => setClickMarker(null)}
          className="bg-white rounded-lg shadow-lg p-2 hover:bg-gray-50 transition-colors"
          title="Clear selection"
        >
          <X className="w-5 h-5 text-gray-600" />
        </button>
        <button
          onClick={() => {
            const map = document.querySelector('.leaflet-container') as any;
            if (map && map._leaflet_map) {
              map._leaflet_map.setView(DEFAULT_MAP_CENTER, DEFAULT_ZOOM, { animate: true });
            }
          }}
          className="bg-white rounded-lg shadow-lg p-2 hover:bg-gray-50 transition-colors"
          title="Center on Lake Winnebago"
        >
          <Navigation className="w-5 h-5 text-dock-blue" />
        </button>
      </div>
    </div>
  );
}
