import type { JobType } from '../types';
import { Anchor, Trash2, Wrench, AlertTriangle, MapPin } from 'lucide-react';

interface JobFiltersProps {
  activeFilters: JobType[];
  showUrgentOnly: boolean;
  onFilterChange: (filters: JobType[]) => void;
  onUrgentToggle: (urgent: boolean) => void;
  jobCounts: { install: number; remove: number; service: number; urgent: number };
}

export default function JobFilters({ activeFilters, showUrgentOnly, onFilterChange, onUrgentToggle, jobCounts }: JobFiltersProps) {
  const toggleFilter = (type: JobType) => {
    if (activeFilters.includes(type)) {
      if (activeFilters.length > 1) {
        onFilterChange(activeFilters.filter(f => f !== type));
      }
    } else {
      onFilterChange([...activeFilters, type]);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4 space-y-4">
      <div className="flex items-center gap-2 mb-3">
        <MapPin className="w-5 h-5 text-dock-blue" />
        <h3 className="font-semibold text-gray-900">Job Types</h3>
      </div>

      <div className="space-y-2">
        <button
          onClick={() => toggleFilter('install')}
          className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all ${
            activeFilters.includes('install')
              ? 'bg-green-50 text-green-700 border-2 border-green-200'
              : 'bg-gray-50 text-gray-600 border-2 border-transparent hover:bg-gray-100'
          }`}
        >
          <div className={`w-3 h-3 rounded-full ${activeFilters.includes('install') ? 'bg-green-500' : 'bg-gray-300'}`} />
          <Anchor className="w-4 h-4" />
          <span className="flex-1 text-left">Install</span>
          <span className="text-xs bg-white px-2 py-0.5 rounded-full shadow-sm">{jobCounts.install}</span>
        </button>

        <button
          onClick={() => toggleFilter('remove')}
          className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all ${
            activeFilters.includes('remove')
              ? 'bg-amber-50 text-amber-700 border-2 border-amber-200'
              : 'bg-gray-50 text-gray-600 border-2 border-transparent hover:bg-gray-100'
          }`}
        >
          <div className={`w-3 h-3 rounded-full ${activeFilters.includes('remove') ? 'bg-amber-500' : 'bg-gray-300'}`} />
          <Trash2 className="w-4 h-4" />
          <span className="flex-1 text-left">Remove</span>
          <span className="text-xs bg-white px-2 py-0.5 rounded-full shadow-sm">{jobCounts.remove}</span>
        </button>

        <button
          onClick={() => toggleFilter('service')}
          className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all ${
            activeFilters.includes('service')
              ? 'bg-blue-50 text-blue-700 border-2 border-blue-200'
              : 'bg-gray-50 text-gray-600 border-2 border-transparent hover:bg-gray-100'
          }`}
        >
          <div className={`w-3 h-3 rounded-full ${activeFilters.includes('service') ? 'bg-blue-500' : 'bg-gray-300'}`} />
          <Wrench className="w-4 h-4" />
          <span className="flex-1 text-left">Service</span>
          <span className="text-xs bg-white px-2 py-0.5 rounded-full shadow-sm">{jobCounts.service}</span>
        </button>

        <div className="pt-2 border-t border-gray-100">
          <button
            onClick={() => onUrgentToggle(!showUrgentOnly)}
            className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all ${
              showUrgentOnly
                ? 'bg-red-50 text-red-700 border-2 border-red-200'
                : 'bg-gray-50 text-gray-600 border-2 border-transparent hover:bg-gray-100'
            }`}
          >
            <div className={`w-3 h-3 rounded-full ${showUrgentOnly ? 'bg-red-500' : 'bg-gray-300'}`} />
            <AlertTriangle className="w-4 h-4" />
            <span className="flex-1 text-left">Urgent Only</span>
            <span className="text-xs bg-white px-2 py-0.5 rounded-full shadow-sm">{jobCounts.urgent}</span>
          </button>
        </div>
      </div>
    </div>
  );
}
