import type { Job, Customer } from '../types';

const API_BASE = '/api';

const toNumber = (v: unknown): number | undefined => {
  if (typeof v === 'number' && Number.isFinite(v)) return v;
  if (typeof v === 'string') {
    const n = Number(v);
    if (Number.isFinite(n)) return n;
  }
  return undefined;
};

const normalizeCustomer = (raw: any): Customer => {
  return {
    id: raw?.id ?? Date.now(),
    name: raw?.name ?? 'Unknown',
    email: raw?.email ?? undefined,
    phone: raw?.phone ?? undefined,
    address: raw?.address ?? '',
    lat: toNumber(raw?.lat ?? raw?.latitude),
    lng: toNumber(raw?.lng ?? raw?.longitude ?? raw?.lon),
    notes: raw?.notes ?? undefined,
    createdAt: raw?.createdAt ?? raw?.created_at ?? new Date().toISOString(),
  };
};

const normalizeJob = (raw: any): Job => {
  const lat = toNumber(raw?.lat ?? raw?.latitude);
  const lng = toNumber(raw?.lng ?? raw?.longitude ?? raw?.lon);
  return {
    id: Number(raw?.id ?? Date.now()),
    customerId: Number(raw?.customerId ?? raw?.customer_id ?? 0),
    dockId: raw?.dockId ?? raw?.dock_id,
    type: (raw?.type ?? 'service') as Job['type'],
    status: (raw?.status ?? 'pending') as Job['status'],
    scheduledDate: raw?.scheduledDate ?? raw?.scheduled_date,
    completedDate: raw?.completedDate ?? raw?.completed_date,
    description: raw?.description ?? raw?.notes ?? raw?.title ?? '',
    estimatedHours: Number(raw?.estimatedHours ?? raw?.estimated_hours ?? 1),
    actualHours: raw?.actualHours ?? raw?.actual_hours,
    materials: raw?.materials,
    cost: toNumber(raw?.cost),
    notes: raw?.notes,
    isUrgent: Boolean(raw?.isUrgent ?? raw?.is_urgent ?? raw?.priority === 'urgent'),
    lat: lat ?? Number.NaN,
    lng: lng ?? Number.NaN,
    createdAt: raw?.createdAt ?? raw?.created_at ?? new Date().toISOString(),
  };
};

async function apiFetch(path: string, options?: RequestInit) {
  const res = await fetch(`${API_BASE}${path}`, {
    headers: { 'Content-Type': 'application/json' },
    ...options,
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({ error: 'Request failed' }));
    throw new Error(err.error || `HTTP ${res.status}`);
  }
  return res.json();
}

// Customers
export async function fetchCustomers(): Promise<Customer[]> {
  const rows = await apiFetch('/customers');
  if (!Array.isArray(rows)) return [];
  return rows.map(normalizeCustomer);
}

export async function createCustomer(data: {
  name: string;
  email: string;
  phone: string;
  address: string;
  lat: number;
  lng: number;
  notes?: string;
}): Promise<Customer> {
  const created = await apiFetch('/customers', {
    method: 'POST',
    body: JSON.stringify(data),
  });
  return normalizeCustomer(created);
}

// Jobs
export async function fetchJobs(): Promise<Job[]> {
  const rows = await apiFetch('/jobs');
  if (!Array.isArray(rows)) return [];
  return rows.map(normalizeJob);
}

export async function createJob(data: {
  customerId: number;
  type: string;
  status: string;
  description: string;
  scheduledDate?: string;
  estimatedHours: number;
  cost?: number;
  isUrgent: boolean;
  lat: number;
  lng: number;
}): Promise<Job> {
  const created = await apiFetch('/jobs', {
    method: 'POST',
    body: JSON.stringify({
      customerId: data.customerId,
      customer_id: data.customerId,
      type: data.type,
      status: data.status,
      title: data.description,
      description: data.description,
      notes: data.description,
      scheduledDate: data.scheduledDate,
      scheduled_date: data.scheduledDate,
      estimatedHours: data.estimatedHours,
      estimated_hours: data.estimatedHours,
      cost: data.cost,
      priority: data.isUrgent ? 'urgent' : 'normal',
      isUrgent: data.isUrgent,
      is_urgent: data.isUrgent,
      lat: data.lat,
      lng: data.lng,
      latitude: data.lat,
      longitude: data.lng,
    }),
  });
  return normalizeJob(created);
}
