import { useState, useEffect } from 'react';
import type { JobType, JobStatus } from '../types';
import { X, Briefcase, Calendar, DollarSign, Clock, AlertTriangle } from 'lucide-react';

interface AddJobModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (job: {
    customerId: string | number;
    type: JobType;
    status: JobStatus;
    description: string;
    scheduledDate?: string;
    estimatedHours: number;
    cost?: number;
    isUrgent: boolean;
    lat: number;
    lng: number;
  }) => void;
  customers: { id: string | number; name: string; lat?: number; lng?: number }[];
  defaultLocation?: { lat: number; lng: number } | null;
}

const DEFAULT_LAT = 44.0247;
const DEFAULT_LNG = -88.5426;

export default function AddJobModal({ isOpen, onClose, onSubmit, customers, defaultLocation }: AddJobModalProps) {
  const getCustomerCoords = (customerId: string | number) => {
    const customer = customers.find(c => String(c.id) === String(customerId));
    return {
      lat: customer?.lat ?? DEFAULT_LAT,
      lng: customer?.lng ?? DEFAULT_LNG,
    };
  };

  const [formData, setFormData] = useState({
    customerId: '' as string | number,
    type: 'install' as JobType,
    status: 'pending' as JobStatus,
    description: '',
    scheduledDate: '',
    estimatedHours: 4,
    cost: '',
    isUrgent: false,
    lat: DEFAULT_LAT,
    lng: DEFAULT_LNG,
  });

  // Reset form when modal opens or customers change
  useEffect(() => {
    if (isOpen && customers.length > 0) {
      const firstCustomer = customers[0];
      const coords = defaultLocation || getCustomerCoords(firstCustomer.id);
      setFormData({
        customerId: firstCustomer.id,
        type: 'install',
        status: 'pending',
        description: '',
        scheduledDate: '',
        estimatedHours: 4,
        cost: '',
        isUrgent: false,
        lat: coords.lat,
        lng: coords.lng,
      });
    }
  }, [isOpen]);

  // Update lat/lng when customer changes
  const handleCustomerChange = (customerId: string | number) => {
    const coords = getCustomerCoords(customerId);
    setFormData(prev => ({ ...prev, customerId, lat: coords.lat, lng: coords.lng }));
  };

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    
    // Validate customerId
    if (!formData.customerId || formData.customerId === '' || formData.customerId === 0) {
      alert('Please select a valid customer');
      return;
    }
    
    // Validate description
    if (!formData.description.trim()) {
      alert('Please enter a job description');
      return;
    }
    
    onSubmit({
      ...formData,
      cost: formData.cost ? parseFloat(String(formData.cost)) : undefined,
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4 bg-black/50">
      <div className="bg-white rounded-xl shadow-xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
        <div className="flex items-center justify-between p-4 border-b border-gray-200">
          <div className="flex items-center gap-2">
            <Briefcase className="w-5 h-5 text-dock-blue" />
            <h2 className="text-lg font-semibold text-gray-900">Add New Job</h2>
          </div>
          <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded-lg transition-colors">
            <X className="w-5 h-5 text-gray-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-4 space-y-4">
          {/* Customer */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Customer *</label>
            <select
              value={formData.customerId}
              onChange={e => handleCustomerChange(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-dock-blue focus:border-transparent"
              required
            >
              <option value="">-- Select a customer --</option>
              {customers.map(c => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
            {customers.length === 0 && (
              <p className="text-xs text-red-500 mt-1">No customers available. Add a customer first.</p>
            )}
          </div>

          {/* Job Type */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Job Type</label>
            <div className="grid grid-cols-3 gap-2">
              {(['install', 'remove', 'service'] as JobType[]).map(type => (
                <button
                  key={type}
                  type="button"
                  onClick={() => setFormData({ ...formData, type })}
                  className={`px-3 py-2 rounded-lg text-sm font-medium capitalize transition-all ${
                    formData.type === type
                      ? type === 'install' ? 'bg-green-100 text-green-700 border-2 border-green-300'
                      : type === 'remove' ? 'bg-amber-100 text-amber-700 border-2 border-amber-300'
                      : 'bg-blue-100 text-blue-700 border-2 border-blue-300'
                      : 'bg-gray-50 text-gray-600 border-2 border-transparent hover:bg-gray-100'
                  }`}
                >
                  {type}
                </button>
              ))}
            </div>
          </div>

          {/* Description */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Description *</label>
            <textarea
              value={formData.description}
              onChange={e => setFormData({ ...formData, description: e.target.value })}
              placeholder="Describe the work needed..."
              rows={3}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-dock-blue focus:border-transparent resize-none"
              required
            />
          </div>

          {/* Status & Date */}
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
              <select
                value={formData.status}
                onChange={e => setFormData({ ...formData, status: e.target.value as JobStatus })}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-dock-blue focus:border-transparent"
              >
                <option value="pending">Pending</option>
                <option value="scheduled">Scheduled</option>
                <option value="in_progress">In Progress</option>
                <option value="completed">Completed</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Scheduled Date</label>
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input
                  type="date"
                  value={formData.scheduledDate}
                  onChange={e => setFormData({ ...formData, scheduledDate: e.target.value })}
                  className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-dock-blue focus:border-transparent"
                />
              </div>
            </div>
          </div>

          {/* Hours & Cost */}
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Est. Hours</label>
              <div className="relative">
                <Clock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input
                  type="number"
                  min="0.5"
                  step="0.5"
                  value={formData.estimatedHours}
                  onChange={e => setFormData({ ...formData, estimatedHours: parseFloat(e.target.value) })}
                  className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-dock-blue focus:border-transparent"
                  required
                />
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Cost ($)</label>
              <div className="relative">
                <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input
                  type="number"
                  min="0"
                  step="0.01"
                  value={formData.cost}
                  onChange={e => setFormData({ ...formData, cost: e.target.value })}
                  placeholder="Optional"
                  className="w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-dock-blue focus:border-transparent"
                />
              </div>
            </div>
          </div>

          {/* Urgent Toggle */}
          <div className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg">
            <button
              type="button"
              onClick={() => setFormData({ ...formData, isUrgent: !formData.isUrgent })}
              className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-all ${
                formData.isUrgent
                  ? 'bg-red-100 text-red-700 border-2 border-red-300'
                  : 'bg-white text-gray-600 border-2 border-gray-200 hover:bg-gray-100'
              }`}
            >
              <AlertTriangle className="w-4 h-4" />
              Mark as Urgent
            </button>
          </div>

          {/* Location */}
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Latitude</label>
              <input
                type="number"
                step="any"
                value={formData.lat}
                onChange={e => setFormData({ ...formData, lat: parseFloat(e.target.value) })}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-dock-blue focus:border-transparent"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Longitude</label>
              <input
                type="number"
                step="any"
                value={formData.lng}
                onChange={e => setFormData({ ...formData, lng: parseFloat(e.target.value) })}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-dock-blue focus:border-transparent"
              />
            </div>
          </div>
          <p className="text-xs text-gray-400">Tip: Click on the map to set location automatically</p>

          {/* Actions */}
          <div className="flex gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-2 bg-dock-blue text-white rounded-lg hover:bg-blue-600 transition-colors font-medium"
            >
              Create Job
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
