import { useState, useMemo, useEffect, useCallback } from 'react';
import type { JobType, Job, Customer } from './types';
import type { GeocodeResult } from './utils/geocode';
import { jobs as demoJobs, customers as demoCustomers } from './data/oshkosh-data';
import Header from './components/Header';
import JobMap from './components/JobMap';
import JobFilters from './components/JobFilters';
import JobList from './components/JobList';
import Dashboard from './components/Dashboard';
import GeocodeSearch from './components/GeocodeSearch';
import AddJobModal from './components/AddJobModal';
import AddCustomerModal from './components/AddCustomerModal';
import { fetchCustomers, createCustomer, fetchJobs, createJob } from './utils/api';
import { MapPin, List, LayoutDashboard, Search, Plus, UserPlus, RefreshCw } from 'lucide-react';

function App() {
  console.log('[App] Rendering started');
  
  const [currentPage, setCurrentPage] = useState('map');
  const [activeFilters, setActiveFilters] = useState<JobType[]>(['install', 'remove', 'service']);
  const [showUrgentOnly, setShowUrgentOnly] = useState(false);
  const [selectedJobId, setSelectedJobId] = useState<number | null>(null);
  const [searchLocation, setSearchLocation] = useState<GeocodeResult | null>(null);
  const [showAddJob, setShowAddJob] = useState(false);
  const [showAddCustomer, setShowAddCustomer] = useState(false);
  const [pendingLocation, setPendingLocation] = useState<{lat: number; lng: number} | null>(null);

  // Data state
  const [jobs, setJobs] = useState<Job[]>(demoJobs);
  const [customers, setCustomers] = useState<Customer[]>(demoCustomers);
  const [_loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [useApi, setUseApi] = useState(true);
  const [initError, setInitError] = useState<string | null>(null);

  // Validate demo data on mount
  useEffect(() => {
    try {
      console.log('[App] Validating demo data...');
      if (!Array.isArray(demoJobs)) throw new Error('demoJobs is not an array');
      if (!Array.isArray(demoCustomers)) throw new Error('demoCustomers is not an array');
      console.log('[App] Demo data OK - jobs:', demoJobs.length, 'customers:', demoCustomers.length);
    } catch (e) {
      const msg = 'Data validation failed: ' + (e as Error).message;
      console.error('[App]', msg);
      setInitError(msg);
    }
  }, []);

  // Load data from API on mount
  useEffect(() => {
    if (!useApi || initError) return;
    console.log('[App] Loading data from API...');
    loadData();
  }, [useApi, initError]);

  const loadData = async () => {
    setLoading(true);
    setError(null);
    try {
      const [fetchedJobs, fetchedCustomers] = await Promise.all([
        fetchJobs().catch((e) => { console.warn('[App] fetchJobs failed:', e); return []; }),
        fetchCustomers().catch((e) => { console.warn('[App] fetchCustomers failed:', e); return []; }),
      ]);
      console.log('[App] API response - jobs:', fetchedJobs.length, 'customers:', fetchedCustomers.length);
      
      // Only use API data if it has records, otherwise keep demo data
      if (fetchedJobs.length > 0) {
        setJobs(fetchedJobs);
      } else {
        console.log('[App] API returned no jobs, keeping demo data');
      }
      
      if (fetchedCustomers.length > 0) {
        setCustomers(fetchedCustomers);
      } else {
        console.log('[App] API returned no customers, keeping demo data');
      }
    } catch (e) {
      const msg = 'Failed to load data from server';
      console.error('[App]', msg, e);
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  const filteredJobs = useMemo(() => {
    try {
      return jobs.filter(job => {
        if (showUrgentOnly && !job.isUrgent) return false;
        return activeFilters.includes(job.type);
      });
    } catch (e) {
      console.error('[App] filteredJobs error:', e);
      return [];
    }
  }, [jobs, activeFilters, showUrgentOnly]);

  const jobCounts = useMemo(() => ({
    install: jobs.filter(j => j.type === 'install').length,
    remove: jobs.filter(j => j.type === 'remove').length,
    service: jobs.filter(j => j.type === 'service').length,
    urgent: jobs.filter(j => j.isUrgent).length,
  }), [jobs]);

  const handleLocationSelect = (location: GeocodeResult) => {
    setSearchLocation(location);
    setCurrentPage('map');
  };

  const handleMapClick = useCallback((lat: number, lng: number) => {
    console.log('[App] Map clicked at:', lat, lng);
    setPendingLocation({ lat, lng });
    setShowAddJob(true);
  }, []);

  const handleAddJob = useCallback(async (jobData: any) => {
    try {
      console.log('[App] Adding job:', jobData);
      
      // Validate customerId - can be string or number
      const customerId = jobData.customerId;
      if (!customerId || customerId === '' || customerId === 0) {
        throw new Error('Please select a valid customer');
      }
      
      // Ensure lat/lng are valid numbers
      const lat = typeof jobData.lat === 'number' ? jobData.lat : parseFloat(jobData.lat);
      const lng = typeof jobData.lng === 'number' ? jobData.lng : parseFloat(jobData.lng);
      if (isNaN(lat) || isNaN(lng)) {
        throw new Error('Invalid coordinates: lat and lng must be valid numbers');
      }
      
      const jobWithCoords = { ...jobData, customerId, lat, lng };
      
      if (useApi) {
        try {
          const newJob = await createJob(jobWithCoords);
          setJobs(prev => [...prev, newJob]);
        } catch (apiErr) {
          console.warn('[App] API failed, falling back to demo mode:', apiErr);
          // Fallback: add to local state
          const newJob: Job = {
            id: Date.now(),
            customerId: jobWithCoords.customerId,
            type: jobWithCoords.type,
            status: jobWithCoords.status,
            description: jobWithCoords.description,
            scheduledDate: jobWithCoords.scheduledDate,
            estimatedHours: jobWithCoords.estimatedHours,
            cost: jobWithCoords.cost,
            isUrgent: jobWithCoords.isUrgent,
            lat: jobWithCoords.lat,
            lng: jobWithCoords.lng,
            createdAt: new Date().toISOString(),
          };
          setJobs(prev => [...prev, newJob]);
        }
      } else {
        const newJob: Job = {
          id: Date.now(),
          customerId: jobWithCoords.customerId,
          type: jobWithCoords.type,
          status: jobWithCoords.status,
          description: jobWithCoords.description,
          scheduledDate: jobWithCoords.scheduledDate,
          estimatedHours: jobWithCoords.estimatedHours,
          cost: jobWithCoords.cost,
          isUrgent: jobWithCoords.isUrgent,
          lat: jobWithCoords.lat,
          lng: jobWithCoords.lng,
          createdAt: new Date().toISOString(),
        };
        setJobs(prev => [...prev, newJob]);
      }
      console.log('[App] Job added successfully');
    } catch (e) {
      const msg = 'Failed to create job: ' + (e as Error).message;
      console.error('[App]', msg);
      alert(msg);
    }
  }, [useApi]);

  const handleAddCustomer = useCallback(async (customerData: any) => {
    try {
      console.log('[App] Adding customer:', customerData);
      if (useApi) {
        const newCustomer = await createCustomer(customerData);
        setCustomers(prev => [...prev, newCustomer]);
      } else {
        const newCustomer: Customer = {
          id: Date.now(),
          ...customerData,
          createdAt: new Date().toISOString(),
        };
        setCustomers(prev => [...prev, newCustomer]);
      }
      console.log('[App] Customer added successfully');
    } catch (e) {
      const msg = 'Failed to create customer: ' + (e as Error).message;
      console.error('[App]', msg);
      alert(msg);
    }
  }, [useApi]);

  // Show init error if data validation failed
  if (initError) {
    return (
      <div className="min-h-screen bg-red-50 flex items-center justify-center p-4">
        <div className="bg-white rounded-xl shadow-lg p-8 max-w-md w-full text-center">
          <h1 className="text-xl font-bold text-red-600 mb-2">Startup Error</h1>
          <p className="text-gray-600 mb-4">{initError}</p>
          <button 
            onClick={() => window.location.reload()}
            className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700"
          >
            Reload
          </button>
        </div>
      </div>
    );
  }

  console.log('[App] Rendering main UI');

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <Header onNavigate={setCurrentPage} currentPage={currentPage} />
      
      {/* API Status Bar */}
      {error && (
        <div className="bg-amber-50 border-b border-amber-200 px-4 py-2 flex items-center justify-between">
          <span className="text-sm text-amber-700">{error} — using demo data</span>
          <div className="flex items-center gap-2">
            <button onClick={loadData} className="text-sm text-amber-700 hover:text-amber-900 flex items-center gap-1">
              <RefreshCw className="w-3 h-3" /> Retry
            </button>
            <button onClick={() => setUseApi(false)} className="text-sm text-amber-700 hover:text-amber-900 underline">
              Use demo data
            </button>
          </div>
        </div>
      )}
      
      <main className="flex-1">
        {currentPage === 'dashboard' && (
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
            <Dashboard jobs={jobs} />
          </div>
        )}

        {currentPage === 'map' && (
          <div className="h-[calc(100vh-64px)] flex">
            {/* Sidebar */}
            <div className="w-80 bg-white border-r border-gray-200 flex flex-col">
              {/* Search - Fixed at top */}
              <div className="p-4 border-b border-gray-200 bg-white">
                <div className="flex items-center gap-2 mb-3">
                  <Search className="w-5 h-5 text-dock-blue" />
                  <h3 className="font-semibold text-gray-900">Find Location</h3>
                </div>
                <GeocodeSearch 
                  onLocationSelect={handleLocationSelect}
                  defaultValue=""
                />
                <p className="text-xs text-gray-400 mt-2">
                  Search any address, lake, or city worldwide
                </p>
              </div>

              {/* Add Buttons */}
              <div className="p-4 border-b border-gray-200 bg-gray-50">
                <div className="grid grid-cols-2 gap-2">
                  <button 
                    onClick={() => setShowAddJob(true)}
                    className="flex items-center justify-center gap-2 px-3 py-2 bg-dock-blue text-white rounded-lg text-sm font-medium hover:bg-blue-600 transition-colors"
                  >
                    <Plus className="w-4 h-4" />
                    Add Job
                  </button>
                  <button 
                    onClick={() => setShowAddCustomer(true)}
                    className="flex items-center justify-center gap-2 px-3 py-2 bg-dock-navy text-white rounded-lg text-sm font-medium hover:bg-gray-800 transition-colors"
                  >
                    <UserPlus className="w-4 h-4" />
                    Add Customer
                  </button>
                </div>
              </div>
              
              {/* Scrollable content */}
              <div className="flex-1 overflow-y-auto p-4 space-y-4">
                <JobFilters
                  activeFilters={activeFilters}
                  showUrgentOnly={showUrgentOnly}
                  onFilterChange={setActiveFilters}
                  onUrgentToggle={setShowUrgentOnly}
                  jobCounts={jobCounts}
                />
                
                <JobList
                  jobs={filteredJobs}
                  selectedJobId={selectedJobId}
                  onJobSelect={setSelectedJobId}
                />
              </div>
            </div>
            
            {/* Map */}
            <div className="flex-1">
              <JobMap
                jobs={jobs}
                activeFilters={activeFilters}
                showUrgentOnly={showUrgentOnly}
                selectedJobId={selectedJobId}
                onJobSelect={setSelectedJobId}
                searchLocation={searchLocation}
                onMapClick={handleMapClick}
              />
            </div>
          </div>
        )}

        {currentPage === 'jobs' && (
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <List className="w-6 h-6 text-dock-blue" />
                <h2 className="text-2xl font-bold text-gray-900">All Jobs</h2>
              </div>
              <button 
                onClick={() => setShowAddJob(true)}
                className="flex items-center gap-2 px-4 py-2 bg-dock-blue text-white rounded-lg text-sm font-medium hover:bg-blue-600 transition-colors"
              >
                <Plus className="w-4 h-4" />
                Add New Job
              </button>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-1">
                <JobFilters
                  activeFilters={activeFilters}
                  showUrgentOnly={showUrgentOnly}
                  onFilterChange={setActiveFilters}
                  onUrgentToggle={setShowUrgentOnly}
                  jobCounts={jobCounts}
                />
              </div>
              <div className="lg:col-span-2">
                <JobList
                  jobs={filteredJobs}
                  selectedJobId={selectedJobId}
                  onJobSelect={setSelectedJobId}
                />
              </div>
            </div>
          </div>
        )}

        {currentPage === 'customers' && (
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-2">
                <MapPin className="w-6 h-6 text-dock-blue" />
                <h2 className="text-2xl font-bold text-gray-900">Customers</h2>
              </div>
              <button 
                onClick={() => setShowAddCustomer(true)}
                className="flex items-center gap-2 px-4 py-2 bg-dock-blue text-white rounded-lg text-sm font-medium hover:bg-blue-600 transition-colors"
              >
                <UserPlus className="w-4 h-4" />
                Add New Customer
              </button>
            </div>
            
            {customers.length === 0 ? (
              <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-8 text-center">
                <LayoutDashboard className="w-12 h-12 mx-auto mb-4 text-gray-300" />
                <p className="text-gray-500 mb-2">No customers yet</p>
                <p className="text-sm text-gray-400">Add your first customer to get started</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {customers.map(customer => (
                  <div key={customer.id} className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
                    <h3 className="font-semibold text-gray-900">{customer.name}</h3>
                    <p className="text-sm text-gray-500 mt-1">{customer.address}</p>
                    {customer.phone && <p className="text-sm text-gray-500">{customer.phone}</p>}
                    {customer.email && <p className="text-sm text-gray-500">{customer.email}</p>}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>

      {/* Modals */}
      <AddJobModal
        isOpen={showAddJob}
        onClose={() => { setShowAddJob(false); setPendingLocation(null); }}
        onSubmit={handleAddJob}
        customers={customers.map(c => ({ id: c.id, name: c.name, lat: c.lat, lng: c.lng }))}
        defaultLocation={pendingLocation}
      />
      
      <AddCustomerModal
        isOpen={showAddCustomer}
        onClose={() => setShowAddCustomer(false)}
        onSubmit={handleAddCustomer}
      />
    </div>
  );
}

export default App;
