import { useMemo } from 'react';
import type { Job } from '../types';
import { Anchor, Trash2, Wrench, AlertTriangle, Calendar, DollarSign, Clock, TrendingUp } from 'lucide-react';

interface DashboardProps {
  jobs: Job[];
}

export default function Dashboard({ jobs }: DashboardProps) {
  const stats = useMemo(() => {
    const total = jobs.length;
    const install = jobs.filter(j => j.type === 'install').length;
    const remove = jobs.filter(j => j.type === 'remove').length;
    const service = jobs.filter(j => j.type === 'service').length;
    const urgent = jobs.filter(j => j.isUrgent).length;
    const completed = jobs.filter(j => j.status === 'completed').length;
    const pending = jobs.filter(j => j.status === 'pending').length;
    const scheduled = jobs.filter(j => j.status === 'scheduled').length;
    const inProgress = jobs.filter(j => j.status === 'in_progress').length;
    const totalRevenue = jobs.reduce((sum, j) => sum + (j.cost || 0), 0);
    const totalHours = jobs.reduce((sum, j) => sum + (j.actualHours || j.estimatedHours || 0), 0);

    return { total, install, remove, service, urgent, completed, pending, scheduled, inProgress, totalRevenue, totalHours };
  }, [jobs]);

  const upcomingJobs = useMemo(() => {
    return jobs
      .filter(j => j.scheduledDate && j.status !== 'completed')
      .sort((a, b) => new Date(a.scheduledDate!).getTime() - new Date(b.scheduledDate!).getTime())
      .slice(0, 5);
  }, [jobs]);

  return (
    <div className="space-y-6">
      {/* Stats Grid */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
          <div className="flex items-center gap-2 mb-2">
            <div className="p-2 bg-blue-50 rounded-lg">
              <Anchor className="w-5 h-5 text-blue-600" />
            </div>
            <span className="text-sm text-gray-500">Total Jobs</span>
          </div>
          <p className="text-2xl font-bold text-gray-900">{stats.total}</p>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
          <div className="flex items-center gap-2 mb-2">
            <div className="p-2 bg-green-50 rounded-lg">
              <TrendingUp className="w-5 h-5 text-green-600" />
            </div>
            <span className="text-sm text-gray-500">Completed</span>
          </div>
          <p className="text-2xl font-bold text-gray-900">{stats.completed}</p>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
          <div className="flex items-center gap-2 mb-2">
            <div className="p-2 bg-amber-50 rounded-lg">
              <Clock className="w-5 h-5 text-amber-600" />
            </div>
            <span className="text-sm text-gray-500">Pending</span>
          </div>
          <p className="text-2xl font-bold text-gray-900">{stats.pending}</p>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
          <div className="flex items-center gap-2 mb-2">
            <div className="p-2 bg-red-50 rounded-lg">
              <AlertTriangle className="w-5 h-5 text-red-600" />
            </div>
            <span className="text-sm text-gray-500">Urgent</span>
          </div>
          <p className="text-2xl font-bold text-gray-900">{stats.urgent}</p>
        </div>
      </div>

      {/* Job Type Breakdown */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-2">
              <Anchor className="w-5 h-5 text-green-600" />
              <span className="font-medium text-gray-900">Installations</span>
            </div>
            <span className="text-2xl font-bold text-green-600">{stats.install}</span>
          </div>
          <div className="w-full bg-gray-100 rounded-full h-2">
            <div className="bg-green-500 h-2 rounded-full" style={{ width: `${stats.total ? (stats.install / stats.total * 100) : 0}%` }} />
          </div>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-2">
              <Trash2 className="w-5 h-5 text-amber-600" />
              <span className="font-medium text-gray-900">Removals</span>
            </div>
            <span className="text-2xl font-bold text-amber-600">{stats.remove}</span>
          </div>
          <div className="w-full bg-gray-100 rounded-full h-2">
            <div className="bg-amber-500 h-2 rounded-full" style={{ width: `${stats.total ? (stats.remove / stats.total * 100) : 0}%` }} />
          </div>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
          <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-2">
              <Wrench className="w-5 h-5 text-blue-600" />
              <span className="font-medium text-gray-900">Services</span>
            </div>
            <span className="text-2xl font-bold text-blue-600">{stats.service}</span>
          </div>
          <div className="w-full bg-gray-100 rounded-full h-2">
            <div className="bg-blue-500 h-2 rounded-full" style={{ width: `${stats.total ? (stats.service / stats.total * 100) : 0}%` }} />
          </div>
        </div>
      </div>

      {/* Revenue & Hours */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
          <div className="flex items-center gap-2 mb-2">
            <DollarSign className="w-5 h-5 text-green-600" />
            <span className="text-sm text-gray-500">Total Revenue</span>
          </div>
          <p className="text-2xl font-bold text-gray-900">${stats.totalRevenue.toLocaleString()}</p>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
          <div className="flex items-center gap-2 mb-2">
            <Clock className="w-5 h-5 text-blue-600" />
            <span className="text-sm text-gray-500">Total Hours</span>
          </div>
          <p className="text-2xl font-bold text-gray-900">{stats.totalHours}h</p>
        </div>
      </div>

      {/* Upcoming Jobs */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-4 border-b border-gray-100">
          <div className="flex items-center gap-2">
            <Calendar className="w-5 h-5 text-dock-blue" />
            <h3 className="font-semibold text-gray-900">Upcoming Jobs</h3>
          </div>
        </div>
        <div className="divide-y divide-gray-50">
          {upcomingJobs.length === 0 ? (
            <div className="p-6 text-center text-gray-500 text-sm">No upcoming scheduled jobs</div>
          ) : (
            upcomingJobs.map(job => (
              <div key={job.id} className="p-4 flex items-center justify-between hover:bg-gray-50">
                <div>
                  <p className="text-sm font-medium text-gray-900 capitalize">{job.type} — {job.description}</p>
                  <p className="text-xs text-gray-500">{new Date(job.scheduledDate!).toLocaleDateString()}</p>
                </div>
                <span className={`text-xs px-2 py-1 rounded-full capitalize ${
                  job.status === 'scheduled' ? 'bg-amber-100 text-amber-700' :
                  job.status === 'in_progress' ? 'bg-blue-100 text-blue-700' :
                  'bg-gray-100 text-gray-700'
                }`}>
                  {job.status.replace('_', ' ')}
                </span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}
