import { useState, useEffect } from 'react';
import { AlertTriangle, X, RefreshCw, Copy, Check } from 'lucide-react';

interface ErrorInfo {
  message: string;
  stack?: string;
  source?: string;
  lineno?: number;
  colno?: number;
  timestamp: string;
  type: 'error' | 'unhandledrejection' | 'react';
}

export function ErrorReporter() {
  const [errors, setErrors] = useState<ErrorInfo[]>([]);
  const [collapsed, setCollapsed] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const handleError = (event: ErrorEvent) => {
      const info: ErrorInfo = {
        message: event.message || 'Unknown error',
        stack: event.error?.stack,
        source: event.filename,
        lineno: event.lineno,
        colno: event.colno,
        timestamp: new Date().toISOString(),
        type: 'error',
      };
      setErrors(prev => [...prev, info]);
      console.error('[ErrorReporter] Caught error:', info);
    };

    const handleRejection = (event: PromiseRejectionEvent) => {
      const info: ErrorInfo = {
        message: event.reason?.message || String(event.reason) || 'Unhandled Promise rejection',
        stack: event.reason?.stack,
        timestamp: new Date().toISOString(),
        type: 'unhandledrejection',
      };
      setErrors(prev => [...prev, info]);
      console.error('[ErrorReporter] Caught rejection:', info);
    };

    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', handleRejection);

    return () => {
      window.removeEventListener('error', handleError);
      window.removeEventListener('unhandledrejection', handleRejection);
    };
  }, []);

  if (errors.length === 0) return null;

  const latest = errors[errors.length - 1];
  const reportText = errors.map((e, i) =>
    `--- Error ${i + 1} (${e.type}) ---\n` +
    `Time: ${e.timestamp}\n` +
    `Message: ${e.message}\n` +
    (e.source ? `Source: ${e.source}:${e.lineno}:${e.colno}\n` : '') +
    (e.stack ? `Stack:\n${e.stack}\n` : '')
  ).join('\n');

  const copyToClipboard = async () => {
    await navigator.clipboard.writeText(reportText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const reload = () => window.location.reload();

  return (
    <div
      style={{
        position: 'fixed',
        top: 16,
        left: '50%',
        transform: 'translateX(-50%)',
        zIndex: 99999,
        maxWidth: 600,
        width: '90vw',
        background: '#fef2f2',
        border: '2px solid #ef4444',
        borderRadius: 12,
        boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)',
        fontFamily: 'system-ui, sans-serif',
      }}
    >
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 12,
          padding: '12px 16px',
          borderBottom: collapsed ? 'none' : '1px solid #fecaca',
          cursor: 'pointer',
        }}
        onClick={() => setCollapsed(!collapsed)}
      >
        <AlertTriangle style={{ width: 20, height: 20, color: '#dc2626', flexShrink: 0 }} />
        <div style={{ flex: 1, minWidth: 0 }}>
          <p style={{ margin: 0, fontWeight: 600, color: '#991b1b', fontSize: 14 }}>
            {errors.length} error{errors.length > 1 ? 's' : ''} caught
          </p>
          <p style={{ margin: '4px 0 0', color: '#7f1d1d', fontSize: 12, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
            {latest.message}
          </p>
        </div>
        <div style={{ display: 'flex', gap: 8, flexShrink: 0 }}>
          <button
            onClick={(e) => { e.stopPropagation(); copyToClipboard(); }}
            style={{ padding: 6, borderRadius: 6, border: 'none', background: '#fee2e2', cursor: 'pointer', display: 'flex', alignItems: 'center' }}
            title="Copy error report"
          >
            {copied ? <Check style={{ width: 14, height: 14, color: '#16a34a' }} /> : <Copy style={{ width: 14, height: 14, color: '#dc2626' }} />}
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); reload(); }}
            style={{ padding: 6, borderRadius: 6, border: 'none', background: '#fee2e2', cursor: 'pointer', display: 'flex', alignItems: 'center' }}
            title="Reload page"
          >
            <RefreshCw style={{ width: 14, height: 14, color: '#dc2626' }} />
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); setErrors([]); }}
            style={{ padding: 6, borderRadius: 6, border: 'none', background: '#fee2e2', cursor: 'pointer', display: 'flex', alignItems: 'center' }}
            title="Dismiss"
          >
            <X style={{ width: 14, height: 14, color: '#dc2626' }} />
          </button>
        </div>
      </div>

      {!collapsed && (
        <div style={{ maxHeight: 400, overflow: 'auto', padding: '12px 16px' }}>
          {errors.map((err, idx) => (
            <div key={idx} style={{ marginBottom: 12, padding: 12, background: '#fff', borderRadius: 8, border: '1px solid #fecaca' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
                <span style={{
                  fontSize: 10,
                  fontWeight: 600,
                  textTransform: 'uppercase',
                  padding: '2px 8px',
                  borderRadius: 4,
                  background: err.type === 'error' ? '#fee2e2' : err.type === 'unhandledrejection' ? '#fef3c7' : '#dbeafe',
                  color: err.type === 'error' ? '#dc2626' : err.type === 'unhandledrejection' ? '#d97706' : '#2563eb',
                }}>
                  {err.type}
                </span>
                <span style={{ fontSize: 11, color: '#9ca3af' }}>
                  {new Date(err.timestamp).toLocaleTimeString()}
                </span>
              </div>
              <p style={{ margin: '0 0 4px', fontSize: 13, fontWeight: 500, color: '#1f2937', wordBreak: 'break-word' }}>
                {err.message}
              </p>
              {err.source && (
                <p style={{ margin: '0 0 4px', fontSize: 11, color: '#6b7280' }}>
                  {err.source}:{err.lineno}:{err.colno}
                </p>
              )}
              {err.stack && (
                <pre style={{
                  margin: '8px 0 0',
                  padding: 8,
                  background: '#f3f4f6',
                  borderRadius: 6,
                  fontSize: 11,
                  color: '#4b5563',
                  overflow: 'auto',
                  maxHeight: 150,
                  whiteSpace: 'pre-wrap',
                  wordBreak: 'break-word',
                }}>
                  {err.stack}
                </pre>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
