import type { Job } from '../types';
import { Anchor, Trash2, Wrench, AlertTriangle, Calendar, Clock, MapPin } from 'lucide-react';

interface JobListProps {
  jobs: Job[];
  selectedJobId: number | null;
  onJobSelect: (jobId: number) => void;
}

export default function JobList({ jobs, selectedJobId, onJobSelect }: JobListProps) {
  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return 'bg-green-100 text-green-700 border-green-200';
      case 'in_progress': return 'bg-blue-100 text-blue-700 border-blue-200';
      case 'scheduled': return 'bg-amber-100 text-amber-700 border-amber-200';
      case 'pending': return 'bg-gray-100 text-gray-700 border-gray-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getJobIcon = (type: string) => {
    switch (type) {
      case 'install': return <Anchor className="w-4 h-4" />;
      case 'remove': return <Trash2 className="w-4 h-4" />;
      case 'service': return <Wrench className="w-4 h-4" />;
      default: return <Wrench className="w-4 h-4" />;
    }
  };

  const getJobColor = (type: string) => {
    switch (type) {
      case 'install': return 'text-green-600 bg-green-50';
      case 'remove': return 'text-amber-600 bg-amber-50';
      case 'service': return 'text-blue-600 bg-blue-50';
      default: return 'text-gray-600 bg-gray-50';
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
      <div className="p-4 border-b border-gray-100">
        <h3 className="font-semibold text-gray-900">Jobs ({jobs.length})</h3>
      </div>
      
      <div className="max-h-[400px] overflow-y-auto">
        {jobs.length === 0 ? (
          <div className="p-8 text-center text-gray-500">
            <MapPin className="w-8 h-8 mx-auto mb-2 text-gray-300" />
            <p className="text-sm">No jobs match current filters</p>
          </div>
        ) : (
          <div className="divide-y divide-gray-50">
            {jobs.map(job => (
              <button
                key={job.id}
                onClick={() => onJobSelect(job.id)}
                className={`w-full text-left p-4 transition-all hover:bg-gray-50 ${
                  selectedJobId === job.id ? 'bg-blue-50 border-l-4 border-blue-500' : 'border-l-4 border-transparent'
                }`}
              >
                <div className="flex items-start gap-3">
                  <div className={`p-2 rounded-lg ${getJobColor(job.type)}`}>
                    {getJobIcon(job.type)}
                  </div>
                  
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-sm font-medium text-gray-900 capitalize">{job.type}</span>
                      {job.isUrgent && (
                        <span className="flex items-center gap-1 text-xs text-red-600 bg-red-50 px-2 py-0.5 rounded-full">
                          <AlertTriangle className="w-3 h-3" />
                          Urgent
                        </span>
                      )}
                    </div>
                    
                    <p className="text-sm text-gray-600 mb-2 line-clamp-2">{job.description}</p>
                    
                    <div className="flex items-center gap-3 text-xs text-gray-500">
                      <span className={`px-2 py-0.5 rounded-full border ${getStatusColor(job.status)} capitalize`}>
                        {job.status.replace('_', ' ')}
                      </span>
                      
                      {job.scheduledDate && (
                        <span className="flex items-center gap-1">
                          <Calendar className="w-3 h-3" />
                          {new Date(job.scheduledDate).toLocaleDateString()}
                        </span>
                      )}
                      
                      {job.estimatedHours && (
                        <span className="flex items-center gap-1">
                          <Clock className="w-3 h-3" />
                          {job.estimatedHours}h
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
