import { useState, useRef } from 'react';
import { Search, MapPin, Loader2, X } from 'lucide-react';
import type { GeocodeResult } from '../utils/geocode';
import { geocodeAddress } from '../utils/geocode';

interface GeocodeSearchProps {
  onLocationSelect: (location: GeocodeResult) => void;
  defaultValue?: string;
}

export default function GeocodeSearch({ onLocationSelect, defaultValue = '' }: GeocodeSearchProps) {
  const [query, setQuery] = useState(defaultValue);
  const [results, setResults] = useState<GeocodeResult[]>([]);
  const [loading, setLoading] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const handleSearch = async (searchQuery: string) => {
    setQuery(searchQuery);
    
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
    }
    
    if (searchQuery.length < 3) {
      setResults([]);
      setShowResults(false);
      return;
    }
    
    debounceRef.current = setTimeout(async () => {
      setLoading(true);
      const result = await geocodeAddress(searchQuery);
      setLoading(false);
      
      if (result) {
        setResults([result]);
        setShowResults(true);
      } else {
        setResults([]);
      }
    }, 500);
  };

  const handleSelect = (location: GeocodeResult) => {
    setQuery(location.displayName);
    setShowResults(false);
    onLocationSelect(location);
  };

  const handleClear = () => {
    setQuery('');
    setResults([]);
    setShowResults(false);
  };

  return (
    <div className="relative">
      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
        <input
          type="text"
          value={query}
          onChange={(e) => handleSearch(e.target.value)}
          placeholder="Search address or lake name..."
          className="w-full pl-10 pr-10 py-2.5 bg-white border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-dock-blue focus:border-transparent"
        />
        {query && (
          <button
            onClick={handleClear}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
          >
            <X className="w-4 h-4" />
          </button>
        )}
        {loading && (
          <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-dock-blue animate-spin" />
        )}
      </div>

      {showResults && results.length > 0 && (
        <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-lg shadow-lg z-50 max-h-60 overflow-y-auto">
          {results.map((result, index) => (
            <button
              key={index}
              onClick={() => handleSelect(result)}
              className="w-full text-left px-4 py-3 hover:bg-gray-50 flex items-start gap-3 border-b border-gray-50 last:border-0"
            >
              <MapPin className="w-4 h-4 text-dock-blue mt-0.5 shrink-0" />
              <div>
                <p className="text-sm text-gray-900 font-medium">{result.displayName}</p>
                <p className="text-xs text-gray-500 mt-0.5">
                  {result.lat.toFixed(4)}, {result.lng.toFixed(4)}
                </p>
              </div>
            </button>
          ))}
        </div>
      )}

      {showResults && !loading && results.length === 0 && query.length >= 3 && (
        <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-lg shadow-lg z-50 p-4 text-center">
          <p className="text-sm text-gray-500">No results found</p>
          <p className="text-xs text-gray-400 mt-1">Try a more specific address</p>
        </div>
      )}
    </div>
  );
}
